PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT (COUNT(DISTINCT ?match) AS ?wins)
WHERE {
  ?match wdt:P710 wd:Q47774 ;
         wdt:P585 ?date ;
         wdt:P1346 wd:Q47774 .
  FILTER (?date > "2018-07-15T00:00:00Z"^^xsd:dateTime)
}
